{
  "subject": {
    "face": {
      "description": "Use uploaded reference image face, keep identity exact. Preserve exact hair color, hairstyle, eyes, lips, eyebrows, skin tone, and all natural facial details. Do not alter identity, beautify, or stylize."
    },
    "expression": "neutral confident expression with relaxed eyes and slightly parted lips",
    "pose": "standing barefoot on yacht deck, body facing forward with head turned slightly sideways, both hands resting naturally on metal railing",
    "body": {
      "build": "slim toned physique",
      "skin_tone": "warm lightly tanned skin"
    },
    "clothing": {
      "outfit": "{argument name="outfit" default="flowing pale yellow asymmetrical cutout dress with tropical orange flower details"}, one-shoulder top design, ruched waist, sheer layered fabric, high slit, cascading ruffle edges",
      "accessories": []
    }
  },
  "environment": {
    "location": "{argument name="location" default="luxury yacht on open water"}",
    "background_elements": [
      "blue ocean water",
      "white yacht railing",
