    "lens": "smartphone portrait lens",
    "depth_of_field": "soft natural background separation",
    "image_quality": "ultra realistic high-resolution social media photo"
  },
  "style": {
    "photography_type": "realistic luxury lifestyle photography",
    "color_palette": "soft ocean blues, pale yellows, warm skin tones, clean whites",
    "filter": "subtle realistic photo filter with authentic skin texture, softened digital sharpness, realistic dynamic range, natural saturation, and true-to-life outdoor lighting",
    "imperfections": [
